import React from 'react';
import { Box, Typography, styled, alpha, Paper, Tabs, Tab } from '@mui/material';
import { CarSpecifications } from '../types';

interface CarSpecificationsIconsProps {
  engine?: string;
  power?: string;
  acceleration?: string;
  maxSpeed?: string;
  color?: string;
  year?: number;
  carSpecifications?: CarSpecifications | null;
  showTabs?: boolean;
}

const SpecCard = styled(Paper)(({ theme }) => ({
  borderRadius: theme.spacing(3),
  padding: theme.spacing(3),
  boxShadow: '0 4px 20px rgba(0,0,0,0.08)',
  overflow: 'hidden',
}));

const SpecContainer = styled(Box)(({ theme }) => ({
  display: 'flex',
  flexWrap: 'wrap',
  justifyContent: 'space-around',
  gap: theme.spacing(2),
  '& > div': {
    flex: '1 1 120px',
    maxWidth: '150px',
    textAlign: 'center',
  }
}));

const SpecItem = styled(Box)(({ theme }) => ({
  display: 'flex',
  flexDirection: 'column',
  alignItems: 'center',
  justifyContent: 'center',
  textAlign: 'center',
  padding: theme.spacing(1.5),
  borderRadius: theme.spacing(2),
  backgroundColor: alpha(theme.palette.primary.main, 0.05),
  '& .icon': {
    color: theme.palette.primary.main,
    marginBottom: theme.spacing(1),
    fontSize: '1.5rem',
  },
}));

const StyledTabs = styled(Tabs)(({ theme }) => ({
  marginBottom: theme.spacing(3),
  '& .MuiTabs-indicator': {
    backgroundColor: theme.palette.primary.main,
    height: 3,
    borderRadius: 3,
  },
  '& .MuiTab-root': {
    textTransform: 'none',
    fontWeight: 600,
    fontSize: '0.9rem',
    minHeight: 40,
    [theme.breakpoints.down('sm')]: {
      padding: '6px 10px',
      minWidth: 'auto',
    },
  },
}));

const CarSpecificationsIcons: React.FC<CarSpecificationsIconsProps> = ({
  engine,
  power,
  acceleration,
  maxSpeed,
  color,
  year,
  carSpecifications,
  showTabs = true
}) => {
  const [tabValue, setTabValue] = React.useState(0);

  const handleTabChange = (_: React.SyntheticEvent, newValue: number) => {
    setTabValue(newValue);
  };

  // Проверяем, есть ли данные из базы
  const hasDBSpecs = carSpecifications !== null && carSpecifications !== undefined;

  // Данные для отображения
  // 1. Двигатель - берем из БД, если есть, или из пропса
  let displayEngine = engine || '';
  if (hasDBSpecs && carSpecifications?.engine) {
    const engineObj = carSpecifications.engine;
    displayEngine = engineObj.type || '';
    if (engineObj.displacement) {
      displayEngine += ` ${engineObj.displacement}`;
    }
  }

  // 2. Мощность - берем из БД, если есть, или из пропса
  let displayPower = power || '';
  if (hasDBSpecs) {
    if (carSpecifications?.power) {
      displayPower = carSpecifications.power;
    } else if (carSpecifications?.engine?.horsepower) {
      displayPower = `${carSpecifications.engine.horsepower} л.с.`;
    }
  }

  // 3. Разгон - берем из БД, если есть, или из пропса
  const displayAcceleration = hasDBSpecs && carSpecifications?.acceleration
    ? carSpecifications.acceleration
    : acceleration || '';

  // 4. Максимальная скорость - берем из БД, если есть, или из пропса
  const displayMaxSpeed = hasDBSpecs && carSpecifications?.topSpeed
    ? carSpecifications.topSpeed
    : maxSpeed || '';

  // 5. Цвет - берем из БД, если есть, или из пропса
  const displayColor = hasDBSpecs && carSpecifications?.exteriorColor
    ? carSpecifications.exteriorColor
    : color || '';

  // 6. Год - берем из БД, если есть, или из пропса
  const displayYear = hasDBSpecs && carSpecifications?.year
    ? carSpecifications.year
    : year || new Date().getFullYear();

  const specsContent = (
    <SpecContainer>
      <Box>
        <SpecItem>
          <Box className="icon">⛽</Box>
          <Typography variant="body2" color="text.secondary">
            Двигатель
          </Typography>
          <Typography variant="body1" fontWeight={600}>
            {displayEngine || "4.4L V8 Twin-Turbo"}
          </Typography>
        </SpecItem>
      </Box>

      <Box>
        <SpecItem>
          <Box className="icon">⚡</Box>
          <Typography variant="body2" color="text.secondary">
            Мощность
          </Typography>
          <Typography variant="body1" fontWeight={600}>
            {displayPower || "625 л.с."}
          </Typography>
        </SpecItem>
      </Box>

      <Box>
        <SpecItem>
          <Box className="icon">⏱️</Box>
          <Typography variant="body2" color="text.secondary">
            Разгон до 100 км/ч
          </Typography>
          <Typography variant="body1" fontWeight={600}>
            {displayAcceleration || "3.8 с до 100 км/ч"}
          </Typography>
        </SpecItem>
      </Box>

      <Box>
        <SpecItem>
          <Box className="icon">🚀</Box>
          <Typography variant="body2" color="text.secondary">
            Макс. скорость
          </Typography>
          <Typography variant="body1" fontWeight={600}>
            {displayMaxSpeed || "290 км/ч"}
          </Typography>
        </SpecItem>
      </Box>

      <Box>
        <SpecItem>
          <Box className="icon">🎨</Box>
          <Typography variant="body2" color="text.secondary">
            Цвет
          </Typography>
          <Typography variant="body1" fontWeight={600}>
            {displayColor || "Черный металлик"}
          </Typography>
        </SpecItem>
      </Box>

      <Box>
        <SpecItem>
          <Box className="icon">📆</Box>
          <Typography variant="body2" color="text.secondary">
            Год выпуска
          </Typography>
          <Typography variant="body1" fontWeight={600}>
            {displayYear || 2023}
          </Typography>
        </SpecItem>
      </Box>
    </SpecContainer>
  );

  if (!showTabs) {
    return specsContent;
  }

  return (
    <SpecCard>
      <StyledTabs
        value={tabValue}
        onChange={handleTabChange}
        variant="scrollable"
        scrollButtons="auto"
      >
        <Tab label="Характеристики" />
        <Tab label="Комплектация" />
      </StyledTabs>

      <Box role="tabpanel" hidden={tabValue !== 0}>
        {tabValue === 0 && specsContent}
      </Box>

      <Box role="tabpanel" hidden={tabValue !== 1}>
        {tabValue === 1 && (
          <Box>
            <Typography variant="body1" color="text.secondary" sx={{ textAlign: 'center', py: 4 }}>
              Информация о комплектации будет доступна позже
            </Typography>
          </Box>
        )}
      </Box>
    </SpecCard>
  );
};

export default CarSpecificationsIcons;
